22.3.2.1 1. AutenticaciГіn JWT Segura
class JWTAuth:
    """AutenticaciГіn JWT con Zero Trust"""

    def create_token(self, user: User) -&gt; str:
        """Crea token con claims mГӯnimos necesarios"""
        payload = {
            "sub": user.id,
            "exp": datetime.utcnow() + timedelta(minutes=15),  # Corto
            "jti": str(uuid.uuid4()),  # Token ID Гәnico
            "iss": "stark-api",  # Emisor
            "aud": "stark-client",  # Audiencia
            "scope": user.permissions  # Permisos mГӯnimos
        }
        return jwt.encode(payload, SECRET_KEY, algorithm="HS256")

    def validate_token(self, token: str) -&gt; dict:
        """Valida token con verificaciГіn estricta"""
        try:
            payload = jwt.decode(
                token, 
                SECRET_KEY, 
                algorithms=["HS256"],
                issuer="stark-api",
                audience="stark-client"
            )
            # Verificar que token no estГЎ revocado
            if self.is_revoked(payload["jti"]):
                raise AuthError("Token revocado")
            return payload
        except jwt.ExpiredSignatureError:
            raise AuthError("Token expirado")
        except jwt.InvalidTokenError:
            raise AuthError("Token invГЎlido")


