class InputValidator:
    """ValidaciГіn defensiva de todas las entradas"""

    def validate_user_input(self, data: dict) -&gt; dict:
        """Valida entrada de usuario con whitelist"""
        allowed_fields = {"name", "email", "password"}
        validated = {}

        for field, value in data.items():
            if field not in allowed_fields:
                raise ValidationError(f"Campo no permitido: {field}")

            # Sanitizar segГәn tipo
            if field == "email":
                validated[field] = self.validate_email(value)
            elif field == "password":
                validated[field] = self.validate_password(value)
            else:
                validated[field] = self.sanitize_string(value)

        return validated

    def sanitize_string(self, value: str) -&gt; str:
        """Sanitiza string contra XSS e inyecciГіn"""
        return html.escape(value.strip())


